<template>
	<view class="con">
		<view class="time">
			<view class="timeItem" v-for="(item,index) in times">
				<view class="timeName" v-text="item.time"></view>
				<view class="point"></view>
			</view>
		</view>
		<view class="manager">
			<view v-for="(item,index) in weel">
				<view class="mItem" v-if="item.business == 1">
					<view class="dateItem" v-for="(ite,idx) in item.times"
						:style="ite.status == 'selected' && getStamp(item.date) >= current? 'background:#fff !important' : '' ">
						<image src="../../static/icons/ring.png" mode=""
							v-if="ite.status == 'selected' && getStamp(item.date) >= current" @click="addNew"></image>
						<image src="../../static/icons/noTime.png" mode=""
							v-if="ite.status == 'unselected' && getStamp(item.date) >= current"></image>
					</view>
				</view>
				<view class="muItem" v-if="item.business == 0">
					<view>休</view>
					<view>業</view>
					<view>日</view>
				</view>
			</view>
		</view>
	</view>
</template>

<script>
	export default {
		name: "week",
		props: ["times", "weekData"],
		data() {
			return {
				weel: [{}, {}, {}, {}, {}, {}, {}],
				current: 0
			};
		},
		created() {
			console.log("asdasdasdasdas", this.weekData)
			this.getCurrent()
		},
		watch: {
			times: function(newVal, oldVal) {
				this.times = newVal; //newVal即是chartData
			},
			weekData: function(newVal, oldVal) {
				console.log("weekNew", newVal)
				let that = this
				let array = JSON.parse(JSON.stringify(newVal))
				let tem = []
				for (let i = 0; i < array.length; i++) {
					if (array[i].orders.length > 0) {
						for (let j = 0; j < array[i].orders.length; j++) {
							let start
							for (let k = 0; k < array[i].times.length; k++) {
								array[i].times[k].status = "selected"
								if (array[i].times[k].time == array[i].orders[j].start_time) {
									array[i].times[k].status = "unselected"
									start = k
								} else {
									if (k > start && k < start + (array[i].orders[j].m / 30)) {
										array[i].times[k].status = "unselected"
									} else {
										array[i].times[k].status = "selected"
									}
								}
							}
						}
					} else {
						for (let k = 0; k < array[i].times.length; k++) {
							array[i].times[k].status = "selected"
						}
					}
					tem.push(array[i])
				}
				console.log("temp", tem)
				setTimeout(function() {
					that.weel = tem
				}, 100)
			}
		},
		methods: {
			getCurrent() {
				let date = new Date()
				let stamp = date.getTime()
				this.current = stamp
			},
			addNew() {
				let that = this
				that.$emit("addNew", 123)
			},
			// 通过日期获取时间戳
			getStamp(date) {
				let da = new Date(date)
				let stamp = da.getTime()
				return stamp
			}
		}
	}
</script>

<style lang="scss">
	.con {
		width: 750upx;
		display: flex;

		.time {
			box-sizing: border-box;
			padding: 0;
			position: relative;
			top: -40upx;

			.timeItem {
				height: 80upx;
				font-size: 24upx;
				font-family: Hiragino Sans-W3, Hiragino Sans;
				font-weight: normal;
				color: #1D1D1F;
				width: 158upx;
				line-height: 80upx;
				display: flex;
				align-items: center;
				justify-content: space-between;
				text-align: center;

				.timeName {
					flex: 1;
					text-align: center;
				}

				.point {
					width: 20upx;
					height: 2upx;
					background-color: #EAEAEA;
				}
			}
		}
	}

	.manager {
		width: 560upx;
		overflow-x: scroll;
		display: flex;
		border-top: none;
		border-left: 2upx solid #EAEAEA;

		.muItem {
			width: 80upx;
			flex-shrink: 0;
			box-sizing: border-box;
			padding: 0;
			position: relative;
			text-align: center;
			background: rgba(249, 249, 249, 0.94);
			border-right: 2upx solid #eaeaea;
			border-top: 2upx solid #eaeaea;
			font-size: 32upx;
			font-family: Hiragino Sans-W3, Hiragino Sans;
			font-weight: normal;
			color: rgba(217, 48, 37, 0.65);
			padding-top: 242upx;
		}

		.mItem {
			width: 80upx;
			flex-shrink: 0;
			box-sizing: border-box;
			padding: 0;
			position: relative;


			.dateItem {
				border: 2upx solid #eaeaea;
				height: 80upx;
				background: rgba(249, 249, 249, 0.94);
				text-align: center;
				box-sizing: border-box;
				display: flex;
				align-items: center;
				justify-content: center;

				image {
					width: 48upx;
					height: 48upx;
				}
			}
		}

	}
</style>
